        updatedAt: new Date().toISOString()
    };
    topics.unshift(topic);
    messages[topic.id] = [];
    currentTopicId = topic.id;
    saveToStorage();
    renderTopicsList();
    renderMessages();
    return topic.id;
}

function addNewTopic() {
    const title = prompt('请输入话题名称：', '新对话');
    if (title) {
        createNewTopic(title);
    }
}

function selectTopic(topicId) {
    currentTopicId = topicId;
    const topic = topics.find(t => t.id === topicId);
    if (topic) {
        topic.updatedAt = new Date().toISOString();
        const index = topics.findIndex(t => t.id === topicId);
        if (index > 0) {
            topics.splice(index, 1);
            topics.unshift(topic);
        }
    }
    saveToStorage();
    renderTopicsList();
    renderMessages();

    // 从服务器加载话题消息
    loadChatFromServer(topicId);
}

async function loadChatFromServer(topicId) {
    try {
        const response = await fetch(`/api/chat/${topicId}`);
        const data = await response.json();

        if (data.messages && data.messages.length > 0) {
            messages[topicId] = data.messages;
            renderMessages();
        }
    } catch (error) {
        console.log('加载历史消息失败，使用本地存储');
    }
