  "originalFile": "// 数据存储
let currentTopicId = null;
let pendingImages = [];
let topics = [];
let messages = {};

// 初始化
document.addEventListener('DOMContentLoaded', () => {
    loadFromStorage();
    if (topics.length === 0) {
        createNewTopic('默认对话');
    } else {
        selectTopic(topics[0].id);
    }
    renderTopicsList();
    renderMessages();
});

// === 话题管理 ===

function createNewTopic(title = '新对话') {
    const topic = {
        id: Date.now().toString(),
        title: title,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
    topics.unshift(topic);
    messages[topic.id] = [];
    currentTopicId = topic.id;
    saveToStorage();
    renderTopicsList();
    renderMessages();
    return topic.id;
}

function addNewTopic() {
    const title = prompt('请输入话题名称：', '新对话');
    if (title) {
        createNewTopic(title);
    }
}

function selectTopic(topicId) {
    currentTopicId = topicId;
    // 更新话题更新时间
    const topic = topics.find(t => t.id === topicId);
    if (topic) {
        topic.updatedAt = new Date().toISOString();
        // 将选中的话题移到最前面
        const index = topics.findIndex(t => t.id === topicId);
        if (index > 0) {
            topics.splice(index, 1);
            topics.unshift(topic);
        }
    }
    saveToStorage();
    renderTopicsList();
    renderMessages();
}

function deleteTopic(topicId, event) {
    event.stopPropagation();
    if (topics.length <= 1) {
        alert('至少保留一个对话');
        return;
    }
    if (confirm('确定删除这个对话吗？')) {
        topics = topics.filter(t => t.id !== topicId);
        delete messages[topicId];
        if (currentTopicId === topicId) {
            currentTopicId = topics[0]?.id;
        }
        saveToStorage();
        renderTopicsList();
        renderMessages();
    }
}

function editTopic(topicId, event) {
    event.stopPropagation();
    const topic = topics.find(t => t.id === topicId);
    if (topic) {
        const newTitle = prompt('请输入新标题：', topic.title);
        if (newTitle && newTitle.trim()) {
            topic.title = newTitle.trim();
            saveToStorage();
            renderTopicsList();
        }
    }
}

function renderTopicsList() {
    const topicsList = document.getElementById('topicsList');
    if (!topicsList) return;

    if (topics.length === 0) {
        topicsList.innerHTML = '<div class="empty-state"><div class="empty-state-icon">📁</div><p>暂无对话</p></div>';
        return;
    }

    topicsList.innerHTML = topics.map(topic => {
        const topicMessages = messages[topic.id] || [];
        const lastMessage = topicMessages[topicMessages.length - 1];
        const preview = lastMessage ? (lastMessage.text ? lastMessage.text.substring(0, 30) : '[图片]') : '暂无消息';
        const time = formatTime(topic.updatedAt);

        return `
            <div class="topic-item ${topic.id === currentTopicId ? 'active' : ''}" 
                 onclick="selectTopic('${topic.id}')">
                <div class="topic-title">${escapeHtml(topic.title)}</div>
                <div class="topic-preview">${escapeHtml(preview)}${preview.length >= 30 ? '...' : ''}</div>
                <div class="topic-time">${time}</div>
                <div class="topic-actions" style="margin-top: 8px; display: flex; gap: 5px;">
                    <button onclick="editTopic('${topic.id}', event)" style="padding: 3px 8px; font-size: 0.75rem; border: none; background: rgba(255,255,255,0.2); color: inherit; border-radius: 4px; cursor: pointer;">编辑</button>
                    <button onclick="deleteTopic('${topic.id}', event)" style="padding: 3px 8px; font-size: 0.75rem; border: none; background: rgba(255,255,255,0.2); color: inherit; border-radius: 4px; cursor: pointer;">删除</button>
                </div>
            </div>
        `;
    }).join('');
}

// === 消息处理 ===

function sendMessage() {
    const input = document.getElementById('messageInput');
    const text = input.value.trim();

    if (!text && pendingImages.length === 0) {
        return;
    }

    if (!currentTopicId) {
        createNewTopic();
    }

    // 添加用户消息
    addMessage({
        type: 'user',
        text: text,
        images: [...pendingImages],
        time: new Date().toISOString()
    });

    // 清空输入和图片
    input.value = '';
    pendingImages = [];
    renderImagePreviews();

    // 模拟AI回复
    setTimeout(() => {
        addMessage({
            type: 'ai',
            text: getAIResponse(text),
            images: [],
            time: new Date().toISOString()
        });

        // 更新话题预览
        const topic = topics.find(t => t.id === currentTopicId);
        if (topic) {
            topic.updatedAt = new Date().toISOString();
            renderTopicsList();
        }
    }, 1000);
}

function addMessage(message) {
    if (!messages[currentTopicId]) {
        messages[currentTopicId] = [];
    }
    messages[currentTopicId].push(message);
    saveToStorage();
    renderMessages();
    scrollToBottom();
}

function renderMessages() {
    const chatMessages = document.getElementById('chatMessages');
    if (!chatMessages) return;

    const topicMessages = messages[currentTopicId] || [];

    if (topicMessages.length === 0) {
        chatMessages.innerHTML = `
            <div class="empty-state">
                <div class="empty-state-icon">💬</div>
                <h3>开始对话</h3>
                <p>发送消息开始聊天</p>
            </div>
        `;
        return;
    }

    chatMessages.innerHTML = topicMessages.map(msg => {
        const imagesHtml = msg.images && msg.images.length > 0 
            ? `<div class="message-images">${msg.images.map(img => `<img src="${img}" onclick="previewImage('${img}')">`).join('')}</div>`
            : '';

        const textHtml = msg.text ? `<div class="message-text">${escapeHtml(msg.text).replace(/\n/g, '<br>')}</div>` : '';

        return `
            <div class="message ${msg.type}">
                ${imagesHtml}
                ${textHtml}
                <div class="message-time">${formatTime(msg.time)}</div>
            </div>
        `;
    }).join('');

    scrollToBottom();
}

function scrollToBottom() {
    const chatMessages = document.getElementById('chatMessages');
    if (chatMessages) {
        chatMessages.scrollTop = chatMessages.scrollHeight;
    }
}

// === 图片处理 ===

function handleImageUpload(event) {
    const files = event.target.files;
    if (!files) return;

    for (const file of files) {
        if (file.type.startsWith('image/')) {
            const reader = new FileReader();
            reader.onload = (e) => {
                pendingImages.push(e.target.result);
                renderImagePreviews();
            };
            reader.readAsDataURL(file);
        }
    }
    // 清空input以便重复选择同一图片
    event.target.value = '';
}

function renderImagePreviews() {
    const previewArea = document.getElementById('imagePreviewArea');
    if (!previewArea) return;

    if (pendingImages.length === 0) {
        previewArea.style.display = 'none';
        previewArea.innerHTML = '';
        return;
    }

    previewArea.style.display = 'flex';
    previewArea.innerHTML = pendingImages.map((img, index) => `
        <div class="preview-item">
            <img src="${img}" alt="preview">
            <button class="remove-btn" onclick="removeImage(${index})">×</button>
        </div>
    `).join('');
}

function removeImage(index) {
    pendingImages.splice(index, 1);
    renderImagePreviews();
}

function previewImage(src) {
    // 可以实现图片预览模态框
    window.open(src, '_blank');
}

// === 输入处理 ===

function handleKeyDown(event) {
    if (event.key === 'Enter' && !event.shiftKey) {
        event.preventDefault();
        sendMessage();
    }
}

function newChat() {
    const title = prompt('请输入对话名称：', '新对话');
    const topicId = createNewTopic(title || '新对话');
    renderTopicsList();
